<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Ubuntu‑like Desktop</title>
<style>
  * { box-sizing:border-box; margin:0; padding:0; font-family:system-ui, sans-serif; }
  html,body,#desktop { height:100%; width:100%; overflow:hidden; background:#1e1e1e; color:#eee; }
  #desktop { position:relative; display:flex; flex-direction:column; }

  /* Taskbar */
  #taskbar {
    height:40px; background:#2c2c2c; border-top:1px solid #3a3a3a;
    display:flex; align-items:center; padding:0 8px; gap:8px; z-index:100;
  }
  #taskbar button {
    background:#3c3c3c; border:1px solid #4a4a4a; color:#ddd;
    padding:6px 12px; border-radius:4px; cursor:pointer; font-size:13px;
  }
  #taskbar button:hover { background:#4a4a4a; }

  /* Window base */
  .window {
    position:absolute; top:60px; left:60px;
    min-width:360px; min-height:240px;
    background:#2b2b2b; border:1px solid #3a3a3a;
    border-radius:6px; overflow:hidden; display:none; flex-direction:column;
    box-shadow:0 4px 12px rgba(0,0,0,.5); z-index:10;
  }
  .win-header {
    height:30px; background:#3c3c3c; border-bottom:1px solid #4a4a4a;
    display:flex; align-items:center; padding:0 8px; gap:8px;
    user-select:none; cursor:default;
  }
  .win-title { font-size:13px; font-weight:600; color:#fff; }
  .win-close {
    margin-left:auto; width:22px; height:22px; border:none; background:transparent;
    color:#bbb; font-size:16px; line-height:1; cursor:pointer; border-radius:3px;
  }
  .win-close:hover { background:#c0392b; color:#fff; }

  /* Files window */
  #files-window .win-content { flex:1; display:flex; flex-direction:column; overflow:hidden; }
  #files-toolbar { height:36px; background:#333; border-bottom:1px solid #444; display:flex; align-items:center; padding:0 8px; gap:8px; }
  #files-toolbar button { background:#444; border:1px solid #555; color:#ddd; padding:4px 10px; border-radius:3px; cursor:pointer; font-size:12px; }
  #files-toolbar button:hover { background:#555; }
  #files-path { flex:1; font-size:13px; color:#ccc; overflow:hidden; text-overflow:ellipsis; white-space:nowrap; }
  #files-list { flex:1; overflow:auto; padding:8px; display:grid; grid-template-columns:repeat(auto-fill, minmax(120px,1fr)); gap:8px; }
  .fs-item {
    background:#3a3a3a; border:1px solid #4a4a4a; border-radius:4px; padding:8px;
    display:flex; flex-direction:column; align-items:center; cursor:pointer; user-select:none;
    transition:background .15s, border-color .15s;
  }
  .fs-item:hover { background:#444; border-color:#5a5a5a; }
  .fs-item.folder { color:#7aa2f7; }
  .fs-item.file { color:#c0caf5; }
  .fs-item .icon { font-size:28px; margin-bottom:4px; }
  .fs-item .name { font-size:12px; text-align:center; word-break:break-word; max-width:100%; }

  /* Notepad window */
  #notepad-window .win-content { flex:1; display:flex; flex-direction:column; overflow:hidden; }
  #tabs { display:flex; background:#333; border-bottom:1px solid #444; overflow-x:auto; }
  .tab {
    padding:6px 14px; background:#3c3c3c; border-right:1px solid #4a4a4a;
    cursor:pointer; font-size:13px; color:#ddd; white-space:nowrap; user-select:none;
  }
  .tab.active { background:#2b2b2b; color:#fff; border-bottom:2px solid #7aa2f7; margin-bottom:-1px; }
  .tab .close-tab { margin-left:8px; font-size:12px; color:#aaa; cursor:pointer; }
  .tab .close-tab:hover { color:#fff; }
  #new-tab { background:#444; border:1px solid #555; color:#ddd; padding:4px 10px; border-radius:3px; cursor:pointer; font-size:12px; margin:4px; }
  #new-tab:hover { background:#555; }
  #editor { flex:1; border:none; outline:none; background:#1e1e1e; color:#d4d4d4; font-family:monospace; font-size:14px; line-height:1.5; padding:12px; resize:none; }
</style>
</head>
<body>
<div id="desktop">
  <div id="taskbar">
    <button id="open-files">Files</button>
    <button id="open-notepad">Notepad</button>
  </div>

  <!-- Files Window -->
  <div id="files-window" class="window">
    <div class="win-header">
      <span class="win-title">Files</span>
      <button class="win-close" aria-label="Close">✕</button>
    </div>
    <div class="win-content">
      <div id="files-toolbar">
        <button id="files-up" title="Up">⬆ Up</button>
        <div id="files-path">/</div>
      </div>
      <div id="files-list"></div>
    </div>
  </div>

  <!-- Notepad Window -->
  <div id="notepad-window" class="window">
    <div class="win-header">
      <span class="win-title">Notepad</span>
      <button class="win-close" aria-label="Close">✕</button>
    </div>
    <div class="win-content">
      <div id="tabs"></div>
      <button id="new-tab">+ New Tab</button>
      <textarea id="editor" spellcheck="false"></textarea>
    </div>
  </div>
</div>

<script>
/* ---------- Fake Filesystem ---------- */
const fsData = {
  bin: {},
  etc: {},
  home: {
    user: {
      Documents: { "notes.txt": null, "report.pdf": null },
      Downloads: { "archive.zip": null },
      Pictures: { "photo.png": null, "wallpaper.jpg": null }
    }
  },
  usr: { bin: {}, lib: {}, share: {} },
  var: { log: {}, cache: {} },
  "readme.txt": null,
  "license": null
};

/* ---------- State ---------- */
let currentPath = []; // array of path segments from root
const filesWindow = document.getElementById('files-window');
const notepadWindow = document.getElementById('notepad-window');
const filesList = document.getElementById('files-list');
const filesPathEl = document.getElementById('files-path');
const filesUpBtn = document.getElementById('files-up');

/* ---------- Window Helpers ---------- */
function showWindow(win) { win.style.display = 'flex'; }
function hideWindow(win) { win.style.display = 'none'; }
document.querySelectorAll('.win-close').forEach(btn => {
  btn.addEventListener('click', () => hideWindow(btn.closest('.window')));
});
document.getElementById('open-files').addEventListener('click', () => showWindow(filesWindow));
document.getElementById('open-notepad').addEventListener('click', () => showWindow(notepadWindow));

/* ---------- Files App ---------- */
function getNode(pathArr) {
  let node = fsData;
  for (const seg of pathArr) node = node[seg];
  return node;
}
function renderFiles() {
  const node = getNode(currentPath);
  filesList.innerHTML = '';
  filesPathEl.textContent = '/' + currentPath.join('/');
  Object.keys(node).sort().forEach(name => {
    const child = node[name];
    const isFolder = child && typeof child === 'object';
    const item = document.createElement('div');
    item.className = 'fs-item ' + (isFolder ? 'folder' : 'file');
    item.dataset.name = name;
    item.dataset.isFolder = isFolder;
    item.innerHTML = `<div class="icon">${isFolder ? '📁' : '📄'}</div><div class="name">${name}</div>`;
    item.addEventListener('dblclick', () => {
      if (isFolder) {
        currentPath.push(name);
        renderFiles();
      }
    });
    filesList.appendChild(item);
  });
}
filesUpBtn.addEventListener('click', () => {
  if (currentPath.length) { currentPath.pop(); renderFiles(); }
});
renderFiles();

/* ---------- Notepad App ---------- */
const tabsContainer = document.getElementById('tabs');
const newTabBtn = document.getElementById('new-tab');
const editor = document.getElementById('editor');

let tabs = []; // {id, title, content}
let activeTabId = null;

function saveTabs() {
  localStorage.setItem('notepadTabs', JSON.stringify({tabs, activeTabId}));
}
function loadTabs() {
  const data = JSON.parse(localStorage.getItem('notepadTabs') || 'null');
  if (data && Array.isArray(data.tabs) && data.tabs.length) {
    tabs = data.tabs;
    activeTabId = data.activeTabId || tabs[0].id;
  } else {
    const id = crypto.randomUUID();
    tabs = [{id, title: 'Untitled', content: ''}];
    activeTabId = id;
    saveTabs();
  }
}
function renderTabs() {
  tabsContainer.innerHTML = '';
  tabs.forEach(t => {
    const tab = document.createElement('div');
    tab.className = 'tab' + (t.id === activeTabId ? ' active' : '');
    tab.dataset.id = t.id;
    tab.innerHTML = `${escapeHtml(t.title)}<span class="close-tab" title="Close">✕</span>`;
    tab.addEventListener('click', e => {
      if (e.target.classList.contains('close-tab')) {
        closeTab(t.id);
      } else {
        activateTab(t.id);
      }
    });
    tabsContainer.appendChild(tab);
  });
}
function activateTab(id) {
  // save current editor content to previous active tab
  const prev = tabs.find(t => t.id === activeTabId);
  if (prev) prev.content = editor.value;
  activeTabId = id;
  const cur = tabs.find(t => t.id === id);
  editor.value = cur ? cur.content : '';
  renderTabs();
  saveTabs();
}
function closeTab(id) {
  if (tabs.length === 1) return; // prevent closing last tab
  const idx = tabs.findIndex(t => t.id === id);
  tabs.splice(idx, 1);
  if (activeTabId === id) activeTabId = tabs[Math.max(0, idx-1)].id;
  activateTab(activeTabId);
}
newTabBtn.addEventListener('click', () => {
  const id = crypto.randomUUID();
  tabs.push({id, title: 'Untitled', content: ''});
  activateTab(id);
});
editor.addEventListener('input', () => {
  const cur = tabs.find(t => t.id === activeTabId);
  if (cur) { cur.content = editor.value; saveTabs(); }
});
function escapeHtml(s) {
  return s.replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
}

// Initialize notepad
loadTabs();
renderTabs();
activateTab(activeTabId);

/* ---------- Optional: simple window drag (visual only) ---------- */
let dragInfo = null;
document.querySelectorAll('.win-header').forEach(header => {
  header.addEventListener('mousedown', e => {
    if (e.target.classList.contains('win-close')) return;
    const win = header.closest('.window');
    dragInfo = {win, offsetX: e.clientX - win.offsetLeft, offsetY: e.clientY - win.offsetTop};
    document.body.style.userSelect = 'none';
  });
});
document.addEventListener('mousemove', e => {
  if (!dragInfo) return;
  const {win, offsetX, offsetY} = dragInfo;
  win.style.left = (e.clientX - offsetX) + 'px';
  win.style.top = (e.clientY - offsetY) + 'px';
});
document.addEventListener('mouseup', () => { dragInfo = null; document.body.style.userSelect = ''; });
</script>
</body>
</html>
